const fs = require('fs');
const path = require('path');
const Joi = require('joi');
const logger = require('../../../common/logger');

let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  const list = Array.isArray(rawTags) ? rawTags : String(rawTags).split(',');
  return list
    .map((tag) => String(tag || '').trim().toLowerCase())
    .filter((tag) => tag);
}

/**
 * Check whether the problem contains at least one of the requested tags.
 * @param {Object} problem
 * @param {Array<string>} tags
 * @returns {boolean}
 */
function problemHasTags(problem, tags) {
  if (!tags || tags.length === 0) {
    return true;
  }
  if (!problem.tags || !Array.isArray(problem.tags)) {
    return false;
  }
  const problemTags = problem.tags.map((t) => String(t).toLowerCase());
  return tags.some((tag) => problemTags.includes(tag));
}

/**
 * Load problems from JSON file and cache them.
 * @returns {Array<Object>} problems
 */
function loadProblems() {
  if (cachedProblems) {
    return cachedProblems;
  }
  const dataPath = path.resolve(__dirname, '../../data/problems.json');
  const raw = fs.readFileSync(dataPath, 'utf8');
  cachedProblems = JSON.parse(raw);
  return cachedProblems;
}

/**
 * Validate and parse query parameters.
 * @param {Object} query
 * @returns {Object} parsed query
 */
function parseQuery(query) {
  const schema = Joi.object({
    difficulty: Joi.string().valid('easy', 'medium', 'hard').optional(),
    tags: Joi.alternatives().try(Joi.string(), Joi.array().items(Joi.string())).optional(),
    limit: Joi.number().integer().min(1).max(MAX_LIMIT).optional(),
    offset: Joi.number().integer().min(0).optional(),
    includeComponents: Joi.boolean().truthy('true').falsy('false').optional()
  });

  const { error, value } = schema.validate(query);
  if (error) {
    throw error;
  }

  return {
    difficulty: value.difficulty || null,
    tags: normalizeTags(value.tags),
    limit: value.limit || MAX_LIMIT,
    offset: value.offset || 0,
    includeComponents: value.includeComponents === true
  };
}

